select p.*, group_concat(concat(oi.product_name, ' x ', oi.quantity) separator '；') as item_summary from product_orders p left join order_items oi on p.order_id = oi.order_id
p.user_id = #{userId} and p.order_status = #{status}
group by p.order_id order by p.create_time desc

